import re

path = 'app/lib/storyContent.js'

with open(path, 'r', encoding='utf-8') as f:
    content = f.read()

new_entry = '''"my-dream-man": `<p>I always wondered if my dream man existed. They say true love can find you anywhere. What I didn\u2019t know was that it would find me at work.</p> <p style="text-indent:1.5em; margin-bottom:0">I was a bottle girl at one of Lagos\u2019 busiest clubs. The kind of place where money moved like liquid \u2014 easy, constant, unremarkable. One night, Danny reserved our VIP section to celebrate his girlfriend\u2019s birthday. The drinks were top-shelf, the food was out of this world, and the energy was exactly what a Lagos party was supposed to be. Loud, lavish, alive.</p> <p style="text-indent:1.5em; margin-bottom:0">It was going well until late into the night, when a man arrived with three others. He walked straight to the birthday girl, pulled her aside, and within minutes the entire mood collapsed. Voices rose. The girlfriend went pale. It became clear \u2014 the man was also her boyfriend. She\u2019d been seeing them both.</p> <p style="text-indent:1.5em; margin-bottom:0">Danny left without a word. I watched him walk out, and somewhere between the table and the exit, his wallet slipped from his pocket. I picked it up and ran after him, catching him just as he reached his car. He took it from my outstretched hand without so much as a glance and drove away.</p> <p style="text-indent:1.5em; margin-bottom:0">I stood in the car park for a moment, then went back inside.</p> <p style="text-indent:1.5em; margin-bottom:0">It\u2019s been three weeks now since the incident. I never saw him again until today. He was having a drink with some friends. He asked to see the girls who had worked the VIP section the night of the birthday. Two of us were on duty. He studied us both quietly before asking if either of us remembered what had happened after he left.</p> <p style="text-indent:1.5em; margin-bottom:0">\u2018I returned your wallet,\u2019 I said.</p> <p style="text-indent:1.5em; margin-bottom:0">Something shifted in his expression. He reached into his jacket, produced a card, and held it out to me.</p> <p style="text-indent:1.5em; margin-bottom:0">\u2018Call me.\u2019</p> <p style="text-indent:1.5em; margin-bottom:0">I took it and didn\u2019t think much of it.</p> <p style="text-indent:1.5em; margin-bottom:0">On my next day off, more out of curiosity than anything else, I called. We spoke briefly, but long enough for me to realise he was entirely different from what I had assumed. I had taken one look at him \u2014 the VIP bookings, the tailored outfits, the ease with which he spent \u2014 and decided I already knew who he was. One of those Lagos big boys who wear their money like a second skin and expect the world to adjust accordingly.</p> <p style="text-indent:1.5em; margin-bottom:0">But he wasn\u2019t that at all. Danny was actually a cool guy.</p> <p style="text-indent:1.5em; margin-bottom:0">We began talking regularly. Casual dates followed \u2014 nothing dramatic, just two people getting to know each other slowly and without pretence. One evening, he told me, gently but honestly, that he thought I should leave the club. Not because he was ashamed, but because he believed the environment didn\u2019t reflect what I was actually worth. When I eventually showed him my CV, he went quiet for a long moment.</p> <p style="text-indent:1.5em; margin-bottom:0">\u2018Why are you still working there?\u2019 he asked.</p> <p style="text-indent:1.5em; margin-bottom:0">He didn\u2019t wait for a full answer before he started helping me look for something better.</p> <p style="text-indent:1.5em; margin-bottom:0">Now, that\u2019s my kind of man. My dream man. And that was how our love story started.</p> <p style="text-indent:1.5em; margin-bottom:0">One morning, in his usual routine, he made me breakfast in bed. I felt a soft tap on my shoulder and heard his voice, low and close \u2014</p> <p style="text-indent:1.5em; margin-bottom:0">\u2018Babe, wake up.\u2019</p> <p style="text-indent:1.5em; margin-bottom:0">I smiled before I opened my eyes.</p> <p style="text-indent:1.5em; margin-bottom:0">It was Nene, my roommate. Standing over me with her arms crossed, the morning already half gone.</p> <p style="text-indent:1.5em; margin-bottom:0">\u2018Wake up. You\u2019re late for work.\u2019</p> <p style="text-indent:1.5em; margin-bottom:0">I lay still for a moment after she left the room, staring at the ceiling.</p> <p style="text-indent:1.5em; margin-bottom:0">My dream man exists. Only in my dreams.</p> <p style="text-indent:1.5em; margin-bottom:0">***</p>`'''

content = re.sub(r'"my-dream-man": `[\s\S]*?`', new_entry, content)

with open(path, 'w', encoding='utf-8') as f:
    f.write(content)

print('Done')
